INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (1, 0.0, 110501, "あうぅ～残念さ～\nマジムンに魂を\n奪われちゃったかな～？", 4, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24015, 10021, "カオリ（サマー）", 4);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (2, 4.0, 110501, "今日は踊りのキレも悪いよ～\nゴーヤーっぽいもの食べて、元気回復さ～！", 4, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24016, 10021, "カオリ（サマー）", 1);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (3, 0.0, 110501, "マジムンだらけで目が回るさ～！\nふらふらさ～！", 4, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24017, 10021, "カオリ（サマー）", 4);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (4, 5.2, 110501, "なんくるない、なんくるない\n次、頑張ればいいんだよ～！\n海で泳いで\nリフレッシュするさー！", 1, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24018, 10021, "カオリ（サマー）", 2);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (5, 4.2, 110501, "恥ずかしいところ\n見られちゃったね～\n水着？　水着のことじゃないよー？", 5, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24019, 10021, "カオリ（サマー）", 6);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (6, 0.0, 110501, "絶好調さ～！　この調子で\n海の平和を取り戻すよ～！\n楽しい夏が待ってるさ～！", 2, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24020, 10021, "カオリ（サマー）", 2);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (7, 6.4, 110501, "何匹で襲ってきたって\n私はマブイを落っことさないよ～！\nくしゅん！　あ……\n今のくしゃみで落っこちたかも～？", 1, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24021, 10021, "カオリ（サマー）", 6);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (8, 0.0, 110501, "ひーやーさーさー♪\n戦いの後は、踊りを踊って\n気分スッキリさ～！", 2, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24022, 10021, "カオリ（サマー）", 2);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (9, 10.08, 110501, "あれ～？　戦ってるうちに\n水着がどっか行っちゃった～？\nねぇキミ、どっかで見なかった～？\nなんで離れるさ～？", 6, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24023, 10021, "カオリ（サマー）", 3);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (10, 5.0, 110501, "まだまだ私は元気だよ～！\nマジムンでもなんでも、\nどんとこーいさー♪", 1, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24024, 10021, "カオリ（サマー）", 2);
INSERT INTO `v1_522cbd34a41d0950113ea3f666e275781f634c5aba1f197a0200f133650b0fa8` VALUES (11, 0.0, 110501, "私の空手は世界最強さ～！\n夏の陽射しと青い海も合わされば、\n向かうところ敵なしだよー！", 2, 0.0, "2019/07/31 12:00:00", 0.0, "2030/12/17 14:59:59", 24, 24025, 10021, "カオリ（サマー）", 2);
